+
+interface AuditQuery {
+  entityType?: string;
+  entity_type?: string;
+  action?: string;
+  from?: string;
+  to?: string;
+}
+
+interface AuditFilter {
+  entityType?: string;
+  action?: string;
+  from?: string;
+  to?: string;
+}
